components.css:
.ds-widget-container { background: #1e1e1e; color: #ffffff; border: 1px solid #333333; border-radius: 8px; padding: 12px; font-family: Inter, system-ui, sans-serif; width: 150px; height: 80px; box-sizing: border-box; display: flex; flex-direction: column; justify-content: space-between; }
.ds-header { display: flex; justify-content: space-between; align-items: center; }
.ds-label { font-size: 10px; font-weight: 500; text-transform: uppercase; color: #969696; letter-spacing: 0.05em; }
.ds-status-dot { width: 6px; height: 6px; border-radius: 50%; background: #2ea44f; }
.ds-numbers { display: flex; align-items: baseline; gap: 4px; }
.ds-display { font-size: 20px; font-weight: 600; color: #ffffff; }
.ds-body { font-size: 12px; color: #969696; }
.ds-progress-track { height: 4px; background: #2d2d2d; border-radius: 2px; overflow: hidden; }
.ds-progress-fill { height: 100%; background: #007acc; border-radius: 2px; transition: width 0.3s ease; }
.ds-footer { font-size: 9px; color: #969696; text-transform: uppercase; letter-spacing: 0.02em; }
